<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Responsive Tooltip</title>
    <link rel="stylesheet" href="styles.css">
</head>
<body>
    <div class="tooltip relative text-center" id="tooltip">
        <div class="tooltip-text relative top-0 right-0 bg-gray-100 p-4">
            <p>This is a tooltip</p>
            <button class="close-button absolute top-1 right-1 text-lg text-gray-400 hover:text-gray-700 focus:outline-none focus:ring focus:ring-gray-300" onclick="closeTooltip()">×</button>
        </div>
    </div>
    <script>
        function closeTooltip() {
            document.getElementById('tooltip').classList.remove('tooltip--open');
        }
    </script>
</body>
</html>
styles.css
@tailwind base;
@tailwind components;
@tailwind utilities;
.tooltip {
   position: relative;
}
.tooltip:hover .tooltip-text {
   display: block;
}
.tooltip-text {
   position: absolute;
   top: 100%;
   left: 50%;
   transform: translateX(-50%);
   background-color: #f9f9f9;
   border: 1px solid #ddd;
   padding: 10px;
   display: none;
}
.tooltip--open .tooltip-text {
   display: block;
}
.close-button {
   cursor: pointer;
}
.tooltip--open .close-button:hover {
   color: gray;
}
